### 2. `src/pages/HomePage.jsx`
This is the main orchestrator. The most important file — ties everything together.

```jsx
import { useState, useEffect, useCallback } from 'react'
import Header from '../components/Header'
import MoodTranslator from '../components/MoodTranslator'
import DirectMode from '../components/DirectMode'
import TasteProfile from '../components/TasteProfile'
import SearchHistory from '../components/SearchHistory'
import AnimeCard from '../components/AnimeCard'
import NeuralLoader from '../components/NeuralLoader'
import { fetchAnilist, fetchTasteProfile, getMoodRecs, getDirectRecs, 
         getSearchHistory, saveSearchHistory } from '../api/client'

export default function HomePage() {
  const [username, setUsername] = useState('')
  const [source, setSource] = useState('anilist')
  const [activeTab, setActiveTab] = useState('mood')
  const [tasteProfile, setTasteProfile] = useState(null)
  const [recommendations, setRecommendations] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [history, setHistory] = useState([])
  const [avoidList, setAvoidList] = useState([])
  const [dismissedIds, setDismissedIds] = useState(new Set())

  useEffect(() => { loadHistory() }, [])

  const handleImport = async () => {
    if (!username.trim()) return
    setLoading(true); setError(null)
    try {
      await fetchAnilist(username)
      const profile = await fetchTasteProfile(username, source)
      setTasteProfile(profile)
    } catch (e) { setError(e.message) }
    finally { setLoading(false) }
  }

  const handleMoodRec = async (filters) => {
    setLoading(true); setError(null)
    try {
      const results = await getMoodRecs({ ...filters, username, source })
      const filtered = results.filter(r => !dismissedIds.has(r.id))
      setRecommendations(filtered)
    } catch (e) { setError(e.message) }
    finally { setLoading(false) }
  }

  const handleDirectRec = async (filters) => {
    setLoading(true); setError(null)
    try {
      const results = await getDirectRecs({ ...filters, username, source })
      const filtered = results.filter(r => !dismissedIds.has(r.id))
      setRecommendations(filtered)
    } catch (e) { setError(e.message) }
    finally { setLoading(false) }
  }

  const handleDismiss = (id) => {
    setDismissedIds(prev => new Set([...prev, id]))
    setRecommendations(prev => prev.filter(r => r.id !== id))
  }

  const handleAvoid = (genre) => {
    setAvoidList(prev => [...prev, genre])
  }

  const loadHistory = async () => {
    try { setHistory(await getSearchHistory()) } catch {}
  }

  const filteredResults = recommendations.filter(r => !dismissedIds.has(r.id))

  return (
    <div className="min-h-screen bg-[#0a0a14] text-white">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        {/* Title */}
        <div className="text-center mb-8">
          <h1 className="text-4xl md:text-5xl font-bold neon-text mb-2">
            ✦ ANIME SOUL WHISPER ✦
          </h1>
          <p className="text-gray-400">Your AI-powered anime discovery engine</p>
        </div>

        {/* Import Section */}
        <div className="cyber-card p-4 mb-8 flex flex-wrap items-center gap-3 justify-center">
          <input
            className="cyber-input px-4 py-2 w-48"
            placeholder="AniList username..."
            value={username}
            onChange={e => setUsername(e.target.value)}
          />
          <select className="cyber-input px-3 py-2" value={source} onChange={e => setSource(e.target.value)}>
            <option value="anilist">AniList</option>
            <option value="mal">MyAnimeList</option>
          </select>
          <button className="cyber-button px-6 py-2" onClick={handleImport} disabled={loading}>
            {loading ? 'Loading...' : '🔮 Import'}
          </button>
        </div>

        {error && <div className="text-red-400 text-center mb-4">⚠️ {error}</div>}

        {/* Tab Switcher */}
        <div className="flex gap-2 mb-6 justify-center">
          <button onClick={() => setActiveTab('mood')}
            className={`px-6 py-2 rounded-lg transition-all ${activeTab === 'mood' ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-400'}`}>
            🌙 Mood Translator
          </button>
          <button onClick={() => setActiveTab('direct')}
            className={`px-6 py-2 rounded-lg transition-all ${activeTab === 'direct' ? 'bg-blue-600 text-white' : 'bg-gray-800 text-gray-400'}`}>
            🎯 Direct Mode
          </button>
        </div>

        {/* Two-column layout */}
        <div className="flex flex-col lg:flex-row gap-6">
          {/* Left: Main content */}
          <div className="flex-1">
            {activeTab === 'mood' ? (
              <MoodTranslator onRecommend={handleMoodRec} loading={loading} 
                results={filteredResults} onDismiss={handleDismiss} onAvoid={handleAvoid} />
            ) : (
              <DirectMode onRecommend={handleDirectRec} loading={loading} 
                results={filteredResults} onDismiss={handleDismiss} onAvoid={handleAvoid} />
            )}

            {/* Results Grid */}
            {filteredResults.length > 0 && (
              <div className="mt-6">
                <h2 className="text-xl neon-text mb-4">✨ Recommendations</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {filteredResults.map(anime => (
                    <AnimeCard key={anime.id} anime={anime}
                      onDismiss={() => handleDismiss(anime.id)}
                      onAvoid={() => anime.genres?.forEach(g => handleAvoid(g))} />
                  ))}
                </div>
              </div>
            )}

            {loading && <div className="mt-8"><NeuralLoader /></div>}

            {!loading && filteredResults.length === 0 && recommendations.length > 0 && (
              <div className="text-center text-gray-500 mt-8">
                All results dismissed. Try a different search!
              </div>
            )}
          </div>

          {/* Right: Sidebar */}
          <div className="w-full lg:w-72 space-y-4">
            <TasteProfile profile={tasteProfile} loading={loading} />
            <SearchHistory history={history} onLoadSearch={loadHistory} />
          </div>
        </div>
      </main>

      <footer className="text-center py-6 text-gray-600 text-xs">
        Anime Soul Whisper • Powered by AniList & Jikan APIs
      </footer>
    </div>
  )
}
```

